function normalizeText(str) {
  return String(str || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^\w\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenize(str) {
  const stopwords = new Set([
    'a','o','e','de','do','da','dos','das','que','para','por','em','no','na','nos','nas',
    'um','uma','uns','umas','com','sem','mais','menos','ja','hoje','voces','você','vc',
    'isso','esse','essa','esta','está','ta','ai','aí','se','ou','como','qual','quais',
    'me','te','lhe','ele','ela','eles','elas','eu'
  ]);

  return normalizeText(str)
    .split(' ')
    .filter(Boolean)
    .filter(token => !stopwords.has(token));
}

function similarityByTokens(a, b) {
  const ta = tokenize(a);
  const tb = tokenize(b);

  if (!ta.length || !tb.length) return 0;

  const setA = new Set(ta);
  const setB = new Set(tb);

  let intersection = 0;
  for (const token of setA) {
    if (setB.has(token)) intersection++;
  }

  const base = Math.max(setA.size, setB.size);
  return base ? intersection / base : 0;
}

