    .replace(/#LAST_INTENT:[\s\S]*$/i, '')
    .replace(/#LEAD_SUMMARY:[\s\S]*$/i, '')
    .trim();
}

function extractLastQuestion(str) {
  const clean = removeTags(str)
    .replace(/\r/g, '')
    .trim();

  if (!clean) return '';

  const lines = clean
    .split('\n')
    .map(s => s.trim())
    .filter(Boolean);

  for (let i = lines.length - 1; i >= 0; i--) {
    if (/\?$/.test(lines[i])) {
      return lines[i];
    }
  }

  const matches = clean.match(/[^.!?\n]*\?/g);
  if (matches && matches.length) {
    return matches[matches.length - 1].trim();
  }

  return '';
}

