const config = library[leadStatus] || library['QUALIFICANDO'];
const chosen = config.attempts[attempt];

if (!chosen) {
  throw new Error(`Nenhuma tentativa encontrada para status=${leadStatus} tentativa=${attempt}`);
}

const previousQuestion =
  $json.last_question ||
  $json.last_followup_message ||
  $json.last_ai_message ||
  '';

let finalChosen = chosen;
let similarity = similarityByTokens(previousQuestion, chosen.message);

// tenta a próxima tentativa se estiver parecido demais
if (similarity >= 0.7 && attempt < 3 && config.attempts[attempt + 1]) {
  finalChosen = config.attempts[attempt + 1];
  similarity = similarityByTokens(previousQuestion, finalChosen.message);
}

const shouldEscalateHuman = similarity >= 0.7 && attempt >= 3;

return [{
  json: {
    ...$json,
    selected_attempt: attempt,
    followup_type: config.followup_type,
    followup_angle: finalChosen.angle,
    fup_message_base: finalChosen.message,
    breakup_message_base: finalChosen.breakup,
    should_send_breakup: attempt >= 3 ? 1 : 0,
    fup_similarity_score: Number(similarity.toFixed(4)),
    should_escalate_humano: shouldEscalateHuman ? 1 : 0
  }
}];

const text =
  $json.clean_answer ||
  $json.mensagem_final ||
  $json.message ||
  $json.output ||
  $json.last_ai_message ||
  '';

function removeTags(str) {
  return String(str || '')
    .replace(/#STATUS:[\s\S]*$/i, '')
    .replace(/#LAST_INTENT:[\s\S]*$/i, '')
    .replace(/#LEAD_SUMMARY:[\s\S]*$/i, '')
    .trim();
}

function extractLastQuestion(str) {
  const clean = removeTags(str)
    .replace(/\r/g, '')
    .trim();

  if (!clean) return '';

  const lines = clean
    .split('\n')
    .map(s => s.trim())
    .filter(Boolean);

  for (let i = lines.length - 1; i >= 0; i--) {
    if (/\?$/.test(lines[i])) {
      return lines[i];
    }
  }

  const matches = clean.match(/[^.!?\n]*\?/g);
  if (matches && matches.length) {
    return matches[matches.length - 1].trim();
  }

  return '';
}

const mensagemSemTags = removeTags(text);
const lastQuestion = extractLastQuestion(text);

return [
  {
    json: {
      ...$json,
      mensagem_sem_tags: mensagemSemTags,
      last_question_extracted: lastQuestion || null,
      is_question_found: lastQuestion ? 1 : 0
    }
  }
];

