const base = $('SET BASE ATIVA FUP').item.json;
const current = $json;

const txt = current.answer || current.message || current.output || '';

const getTag = (label) => {
  const regex = new RegExp(`#${label}:\\s*([^\\n\\r#]+)`, 'i');
  return (txt.match(regex)?.[1] || '').trim();
};

const getSummary = () => {
  const m = txt.match(/#LEAD_SUMMARY:\s*([\s\S]*)/i);
  return (m?.[1] || '').trim();
};

return [
  {
    json: {
      ...base,
      ...current,
      last_ai_message: txt,
      lead_status: getTag('STATUS') || current.lead_status || base.lead_status || '',
      last_intent: getTag('LAST_INTENT') || current.last_intent || base.last_intent || '',
      lead_summary: getSummary() || current.lead_summary || base.lead_summary || '',
      clean_answer: txt.replace(/\n?#STATUS:[\s\S]*/i, '').trim() || current.active_fup_base || ''
    }
  }
];
